/// <summary>
/// The class <c>ETG_AgreementGenerateReleaseOrder_Extension</c> is used to handle the COC methods related to <c>AgreementGenerateReleaseOrder</c> class.
/// </summary>
[ExtensionOf(classstr(AgreementGenerateReleaseOrder))]
final class ETG_AgreementGenerateReleaseOrder_Extension
{
}

Method.Source:
/// <summary>
///    Validates that the provided quantity can be released from the specified
///    <c>AgreementLineQuantityCommitment</c> record.
/// </summary>
/// <param name="_quantityToValidate">
///    The release line quantity to validate.
/// </param>
/// <param name="_agreementLineQuantityCommitment">
///    The record ID of the <c>AgreementLineQuantityCommitment</c> record from which to release.
/// </param>
/// <returns>
///    true if the requested quantity can be released; otherwise, false.
/// </returns>
/// <remarks>
///    Quantities that are less or equal to 0 are considered as valid for release.
/// </remarks>
public static boolean validateQty(UnitQty _quantityToValidate,
                                  AgreementLineQuantityCommitment _agreementLineQuantityCommitment)
{
    boolean ret = next validateQty(_quantityToValidate, _agreementLineQuantityCommitment);

    // Only if we have agreement line to validate quantity against....
    if (ret && _agreementLineQuantityCommitment)
    {
        Qty toleranceQty = (_agreementLineQuantityCommitment.CommitedQuantity * _agreementLineQuantityCommitment.ETG_ReleaseOrderUpperLimit) / 100;
        // Quantity should be validated against remaining quantity plus tolerance
        if (_quantityToValidate > _agreementLineQuantityCommitment.quantityRemainingRelease() + toleranceQty)
        {
            if(_agreementLineQuantityCommitment.ETG_ToleranceAction == ETG_ToleranceAction::Stop)
            {
                throw error('@ETG:ReleaseOrderQtyValidationMsg');
            }
            else if(_agreementLineQuantityCommitment.ETG_ToleranceAction == ETG_ToleranceAction::Warning)
            {
                Warning('@ETG:ReleaseOrderQtyValidationMsg');
            }
        }
    }
    return ret;
}
